// src/router/index.js
import Vue from 'vue';
import VueRouter from 'vue-router';
import Templates from '../pages/TemplateVue.vue';  // PlantList.vue 경로

Vue.use(VueRouter);

const routes = [
    {
        path: '/sample',
        name: 'sample',
        component: Templates
    },
    // 다른 라우트들 추가 가능
];

const router = new VueRouter({
    mode: 'history',  // 브라우저의 history 모드 사용 (예: /plants)
    routes
});

export default router;
