<template>
  <div>
    <h1>Plant List</h1>
    <ul>
      <li v-for="plant in plants" :key="plant.id">
        {{ plant.id }}
      </li>
    </ul>
  </div>
</template>

<script>
import axios from 'axios';

export default {
  data() {
    return {
      plants: []
    };
  },
  mounted() {
    this.fetchPlants();
  },
  methods: {
    async fetchPlants() {
      try {
        const response = await axios.get('http://localhost:8080/api/template/getRoleList');
        this.plants = response.data;
        console.log(response.data);
        console.log((this.plants));
      } catch (error) {
        console.error('Error fetching plants:', error);
      }
    }
  }
};
</script>

